mapper.select:
select count(1)
from dms_registration dr
inner join sms_skd skd on dr.skd_id = skd.id
where dr.attendance_date = #{day}
  and dr.status <> #{canceledStatus}
  and skd.staff_id = #{staffId}

select count(1)
from dms_registration dr
where dr.attendance_date = #{day}
  and dr.status <> #{canceledStatus}
  and dr.dept_id = #{deptId}

select count(1)
from dms_registration dr
where dr.attendance_date = #{day}
  and dr.status <> #{canceledStatus}

select dr.attendance_date as dt, count(1) as cnt
from dms_registration dr
where dr.attendance_date between #{start} and #{end}
  and dr.status <> #{canceledStatus}
group by dr.attendance_date
order by dr.attendance_date
